<?php require_once __DIR__.'/includes/auth_check.php';$title='Dashboard Atlas';include __DIR__.'/includes/admin_header.php';$q=['week'=>'SELECT COUNT(*) c FROM leads WHERE created_at>=DATE_SUB(NOW(),INTERVAL 7 DAY)','cars'=>'SELECT COUNT(*) c FROM cars','pending'=>"SELECT COUNT(*) c FROM leads WHERE status='new'",'available'=>"SELECT COUNT(*) c FROM cars WHERE status='available'"];$counts=[];foreach($q as $k=>$sql){$s=$pdo->prepare($sql);$s->execute();$counts[$k]=$s->fetch()['c'];}$r=$pdo->prepare('SELECT l.*,c.name car_name FROM leads l JOIN cars c ON c.id=l.car_id ORDER BY l.created_at DESC LIMIT 8');$r->execute();?><h1>Tableau de bord</h1><div class="stats"><div><strong><?=$counts['week']?></strong><span>Leads cette semaine</span></div><div><strong><?=$counts['cars']?></strong><span>Voitures</span></div><div><strong><?=$counts['pending']?></strong><span>Demandes en attente</span></div><div><strong><?=$counts['available']?></strong><span>Disponibles</span></div></div><h2>Leads récents</h2><table><tr><th>Client</th><th>Voiture</th><th>Ville</th><th>Statut</th><th>Date</th></tr><?php foreach($r as $x):?><tr><td><?=e($x['full_name'])?></td><td><?=e($x['car_name'])?></td><td><?=e($x['pickup_city'])?></td><td><span class="badge <?=e($x['status'])?>"><?=e(status_label($x['status']))?></span></td><td><?=e($x['created_at'])?></td></tr><?php endforeach;?></table><?php include __DIR__.'/includes/admin_footer.php';?>